t.SeccompProfile != nil {\n280: \t\treturn fieldSeccompProfile(containerSecContext.SeccompProfile, m.seccompProfileRoot, fallbackToRuntimeDefault)\n281: \t}\n282: \n283: \t// when container seccomp is not defined, try to apply from pod field\n284: \tif podSecContext != nil \u0026\u0026 podSecContext.SeccompProfile != nil {\n285: \t\treturn fieldSeccompProfile(podSecContext.SeccompProfile, m.seccompProfileRoot, fallbackToRuntimeDefault)\n286: \t}\n287: \n288: \tif fallbackToRuntimeDefault {\n289: \t\treturn \u0026runtimeapi.SecurityProfile{\n290: \t\t\tProfileType: runtimeapi.SecurityProfile_RuntimeDefault,\n291: \t\t}, nil\n292: \t}\n293: \n294: \treturn \u0026runtimeapi.SecurityProfile{\n295: \t\tProfileType: runtimeapi.SecurityProfile_Unconfined,\n296: \t}, nil\n297: }\n298: \n299: func getAppArmorProfile(pod *v1.Pod, container *v1.Container) (*runtimeapi.SecurityProfile, string, error) {\n300: \tprofile := apparmor.GetProfile(pod, container)\n301: \tif profile == nil {\n302: \t\treturn nil, \"\", nil\n303: \t}\n304: \n305: \tvar (\n306: \t\tsecurityProfile   *runtimeapi.SecurityProfile\n307: \t\tdeprecatedProfile string // Deprecated apparmor profile format, still provided for backwards compatibility with older runtimes.\n308: \t)\n309: \n310: \tswitch profile.Type {\n311: \tcase v1.AppArmorProfileTypeRuntimeDefault:\n312: \t\tsecurityProfile = \u0026runtimeapi.SecurityProfile{\n313: \t\t\tProfileType: runtimeapi.SecurityProfile_RuntimeDefault,\n314: \t\t}\n315: \t\tdeprecatedProfile = v1.DeprecatedAppArmorBetaProfileRuntimeDefault\n316: \n317: \tcase v1.AppArmorProfileTypeUnconfined:\n318: \t\tsecurityProfile = \u0026runtimeapi.SecurityProfile{\n319: \t\t\tProfileType: runtimeapi.SecurityProfile_Unconfined,\n320: \t\t}\n321: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/kubernetes--v1.32.0@d17b464c6fcd3273e4b1f695890bf0af7d5b272d/-/blob/pkg/kubelet/kuberuntime/helpers.go%3FL240-320"}", "annotations": null, "meta": null}], "structuredContent": 