244: func fieldSeccompProfile(scmp *v1.SeccompProfile, profileRootPath string, fallbackToRuntimeDefault bool) (*runtimeapi.SecurityProfile, error) {
245: 	if scmp == nil {
246: 		if fallbackToRuntimeDefault {
247: 			return &runtimeapi.SecurityProfile{
248: 				ProfileType: runtimeapi.SecurityProfile_RuntimeDefault,
249: 			}, nil
250: 		}
251: 		return &runtimeapi.SecurityProfile{
252: 			ProfileType: runtimeapi.SecurityProfile_Unconfined,
253: 		}, nil
254: 	}
255: 	if scmp.Type == v1.SeccompProfileTypeRuntimeDefault {
256: 		return &runtimeapi.SecurityProfile{
257: 			ProfileType: runtimeapi.SecurityProfile_RuntimeDefault,
258: 		}, nil
259: 	}
260: 	if scmp.Type == v1.SeccompProfileTypeLocalhost {
261: 		if scmp.LocalhostProfile != nil && len(*scmp.LocalhostProfile) > 0 {
262: 			fname := filepath.Join(profileRootPath, *scmp.LocalhostProfile)
263: 			return &runtimeapi.SecurityProfile{
264: 				ProfileType:  runtimeapi.SecurityProfile_Localhost,
265: 				LocalhostRef: fname,
266: 			}, nil
267: 		} else {
268: 			return nil, fmt.Errorf("localhostProfile must be set if seccompProfile type is Localhost.")
269: 		}
270: 	}
271: 	return &runtimeapi.SecurityProfile{
272: 		ProfileType: runtimeapi.SecurityProfile_Unconfined,
273: 	}, nil
274: }
