189: var (
190: 	// These *must* be kept in sync with moby/moby.
191: 	// https://github.com/moby/moby/blob/master/oci/defaults.go#L105-L124
192: 	// @jessfraz will watch changes to those files upstream.
193: 	defaultMaskedPaths = []string{
194: 		"/proc/asound",
195: 		"/proc/acpi",
196: 		"/proc/kcore",
197: 		"/proc/keys",
198: 		"/proc/latency_stats",
199: 		"/proc/timer_list",
200: 		"/proc/timer_stats",
201: 		"/proc/sched_debug",
202: 		"/proc/scsi",
203: 		"/sys/firmware",
204: 		"/sys/devices/virtual/powercap",
205: 	}
206: 	defaultReadonlyPaths = []string{
207: 		"/proc/bus",
208: 		"/proc/fs",
209: 		"/proc/irq",
210: 		"/proc/sys",
211: 		"/proc/sysrq-trigger",
212: 	}
