215: // ConvertToRuntimeMaskedPaths converts the ProcMountType to the specified or default
216: // masked paths.
217: func ConvertToRuntimeMaskedPaths(opt *v1.ProcMountType) []string {
218: 	if opt != nil && *opt == v1.UnmaskedProcMount {
219: 		// Unmasked proc mount should have no paths set as masked.
220: 		return []string{}
221: 	}
222: 
223: 	// Otherwise, add the default masked paths to the runtime security context.
224: 	return defaultMaskedPaths
225: }
226: 
227: // ConvertToRuntimeReadonlyPaths converts the ProcMountType to the specified or default
228: // readonly paths.
229: func ConvertToRuntimeReadonlyPaths(opt *v1.ProcMountType) []string {
230: 	if opt != nil && *opt == v1.UnmaskedProcMount {
231: 		// Unmasked proc mount should have no paths set as readonly.
232: 		return []string{}
233: 	}
234: 
235: 	// Otherwise, add the default readonly paths to the runtime security context.
236: 	return defaultReadonlyPaths
237: }
