317: // HasPrivilegedContainer returns true if any of the containers in the pod are privileged.
318: func HasPrivilegedContainer(pod *v1.Pod) bool {
319: 	var hasPrivileged bool
320: 	podutil.VisitContainers(&pod.Spec, podutil.AllFeatureEnabledContainers(), func(c *v1.Container, containerType podutil.ContainerType) bool {
321: 		if c.SecurityContext != nil && c.SecurityContext.Privileged != nil && *c.SecurityContext.Privileged {
322: 			hasPrivileged = true
323: 			return false
324: 		}
325: 		return true
326: 	})
327: 	return hasPrivileged
328: }
