330: // HasWindowsHostProcessContainer returns true if any of the containers in a pod are HostProcess containers.
331: func HasWindowsHostProcessContainer(pod *v1.Pod) bool {
332: 	var hasHostProcess bool
333: 	podutil.VisitContainers(&pod.Spec, podutil.AllFeatureEnabledContainers(), func(c *v1.Container, containerType podutil.ContainerType) bool {
334: 		if sc.HasWindowsHostProcessRequest(pod, c) {
335: 			hasHostProcess = true
336: 			return false
337: 		}
338: 		return true
339: 	})
340: 
341: 	return hasHostProcess
342: }
