344: // AllContainersAreWindowsHostProcess returns true if all containers in a pod are HostProcess containers.
345: func AllContainersAreWindowsHostProcess(pod *v1.Pod) bool {
346: 	allHostProcess := true
347: 	podutil.VisitContainers(&pod.Spec, podutil.AllFeatureEnabledContainers(), func(c *v1.Container, containerType podutil.ContainerType) bool {
348: 		if !sc.HasWindowsHostProcessRequest(pod, c) {
349: 			allHostProcess = false
350: 			return false
351: 		}
352: 		return true
353: 	})
354: 
355: 	return allHostProcess
356: }
